class Solution {
    TreeNode* build(vector<int>& a,int l,int r){
        if(l>r) return nullptr;
        int mx=l; for(int i=l+1;i<=r;i++) if(a[i]>a[mx]) mx=i;
        TreeNode* n=new TreeNode(a[mx]);
        n->left=build(a,l,mx-1); n->right=build(a,mx+1,r); return n;
    }
public:
    TreeNode* constructMaximumBinaryTree(vector<int>& nums){ return build(nums,0,nums.size()-1); }
};
